import{_ as e,o as s,c as t,a2 as o}from"./chunks/framework.BS3ZfcoS.js";const d=JSON.parse('{"title":"温骏轩调研","description":"","frontmatter":{"title":"温骏轩调研","author":"","collection":"调研报告","series_order":2,"total_chars":3361},"headers":[],"relativePath":"reports/wen-junxuan-report.md","filePath":"reports/wen-junxuan-report.md"}'),r={name:"reports/wen-junxuan-report.md"};function p(n,a,l,h,i,c){return s(),t("div",null,[...a[0]||(a[0]=[o('<div class="page-toc"><p class="page-toc-title">📑 本页目录</p>     <a href="#s-4" class="page-toc-link">1.3 更新频率与创作形式</a><a href="#s-5" class="page-toc-link">2. 核心思想体系</a>     <a href="#s-6" class="page-toc-link">2.1 地缘研究方法论</a>     <a href="#s-7" class="page-toc-link">2.2 核心理论框架：三层结构</a>     <a href="#s-8" class="page-toc-link">2.3 核心逻辑链</a><a href="#s-9" class="page-toc-link">3. 主要作品清单</a>     <a href="#s-10" class="page-toc-link">3.1 出版书籍</a>     <a href="#s-11" class="page-toc-link">3.2 网络连载系列</a><a href="#s-12" class="page-toc-link">4. 体系性分析：看见→判断→行动→验证</a>     <a href="#s-13" class="page-toc-link">4.1 看见环节：5/5</a>     <a href="#s-14" class="page-toc-link">4.2 判断环节：4.5/5</a>     <a href="#s-15" class="page-toc-link">4.3 行动环节：2/5</a>     <a href="#s-16" class="page-toc-link">4.4 验证环节：4/5</a><a href="#s-17" class="page-toc-link">5. 闭环度分析</a><a href="#s-18" class="page-toc-link">6. 可优化性分析</a>     <a href="#s-19" class="page-toc-link">6.1 三个补充方向</a>     <a href="#s-20" class="page-toc-link">6.2 可优化性评估：4/5</a><a href="#s-21" class="page-toc-link">7. 核心概念/命题清单</a><a href="#s-22" class="page-toc-link">8. 萃取建议</a>     <a href="#s-23" class="page-toc-link">8.1 书名建议</a>     <a href="#s-24" class="page-toc-link">8.2 结构建议</a><a href="#s-25" class="page-toc-link">导论：地缘是一种&quot;元视角&quot;</a><a href="#s-26" class="page-toc-link">结语：地缘视角是一种&quot;活的方法&quot;</a>     <a href="#s-27" class="page-toc-link">8.3 需要填充的空白</a><a href="#s-28" class="page-toc-link">9. 关键引用/金句</a><a href="#s-30" class="page-toc-link">10. 调研总结</a></div><p><strong>温骏轩深度调研报告</strong></p><p>地缘政治/地缘战略领域知识创作者萃取前置研究</p><p>──────────────────────────────────────</p><p>**六维评分：**体系性4.5 | 独创性4.5 | 闭环度3.5 | 可优化性4 | 内容量4.5 | 跨域迁移3.5</p><p>**综合得分：**<strong>4.42 / 5.0</strong> ——14位候选人中排名第一的萃取目标</p><p>**核心Gap：**闭环度3.5（地缘分析强但缺少行动闭环，从地缘→商业/个人决策的迁移不足）</p><p>**可优化性4：**地缘框架可以向商业迁移 + 补行动闭环</p><p>调研日期：2026年7月13日</p><h3 id="s-4" tabindex="-1">1.3 更新频率与创作形式 <a class="header-anchor" href="#s-4" aria-label="Permalink to &quot;1.3 更新频率与创作形式 {#s-4}&quot;">​</a></h3><p>**更新频率：**每周更新（公众号固定节奏），天涯时代基本每天半夜12点前后更新，每天只睡4-5小时</p><p>**主要创作形式：**长篇连载文章 + 原创地图 + 音频播客 + 出版书籍</p><p>**创作周期：**2009年至今，持续17年，累计产出近千万字，超过700张自制地图</p><h2 id="s-5" tabindex="-1">2. 核心思想体系 <a class="header-anchor" href="#s-5" aria-label="Permalink to &quot;2. 核心思想体系 {#s-5}&quot;">​</a></h2><h3 id="s-6" tabindex="-1">2.1 地缘研究方法论 <a class="header-anchor" href="#s-6" aria-label="Permalink to &quot;2.1 地缘研究方法论 {#s-6}&quot;">​</a></h3><p><strong>核心方法论：</strong></p><p><em>通过深入浅出的语言，运用简单明确的逻辑，以地缘为角度，以历史为参考，相对客观地解读我们身边的政治文化等现象。</em></p><p>核心是找到一个“更加恒定的量”来洞穿历史和现实——这个量就是“地缘”。地理环境才是比帝王的个人选择更持久的底层变量。</p><p><strong>“地缘”的定义：</strong></p><p><em>&#39;地&#39;是环境，&#39;缘&#39;指人与人之间的关系。结合起来，就是以地理环境等客观因素为基础，研究以群体为单位的&#39;人&#39;，以及群体之间的关系。</em></p><p><strong>关键辨析：这不是地理决定论。</strong> 温骏轩明确反复强调：“研究地缘学说的目的，并不在于否定人的作用，而在于正视环境的影响力，然后因势利导。”</p><h3 id="s-7" tabindex="-1">2.2 核心理论框架：三层结构 <a class="header-anchor" href="#s-7" aria-label="Permalink to &quot;2.2 核心理论框架：三层结构 {#s-7}&quot;">​</a></h3><p><strong>第一层：地缘板块论（宏观框架）</strong></p><p>融合麦金德“世界岛论”、马汉“海权论”、斯皮克曼“边缘地带理论”，创造性提出“新世界岛论”——五个一类地缘政治板块：美国（新世界岛中心）、中国、俄国、印度、欧盟（三大边缘地带）。三个外围国家：英国、日本、澳大利亚。</p><p><strong>第二层：区域地缘解构（中观分析）</strong></p><p>将全球拆解为可操作的地缘板块，逐一分析内部结构、资源禀赋、边界矛盾、历史演变。</p><p><strong>第三层：具体历史事件地缘解读（微观解释）</strong></p><p>用地缘视角重新解读熟悉的历史事件——为什么关羽失荆州？为什么印度种姓制度绵延至今？为什么伊朗是什叶派国家？</p><h3 id="s-8" tabindex="-1">2.3 核心逻辑链 <a class="header-anchor" href="#s-8" aria-label="Permalink to &quot;2.3 核心逻辑链 {#s-8}&quot;">​</a></h3><p>**看见：**地理环境 → 资源禀赋 → 板块结构</p><p>**判断：**结构约束 → 博弈空间 → 战略选择</p><p>**行动：**历史事件 → 大国决策（仅到国家/群体层面，缺个人/商业层）</p><p>**验证：**精准预测（南海、英国脱欧、台海关系等已被历史验证）</p><p><strong>核心缺失：从“看见地缘规律”到“个人如何利用地缘规律做决策”之间存在断裂</strong></p><h2 id="s-9" tabindex="-1">3. 主要作品清单 <a class="header-anchor" href="#s-9" aria-label="Permalink to &quot;3. 主要作品清单 {#s-9}&quot;">​</a></h2><h3 id="s-10" tabindex="-1">3.1 出版书籍 <a class="header-anchor" href="#s-10" aria-label="Permalink to &quot;3.1 出版书籍 {#s-10}&quot;">​</a></h3><h3 id="s-11" tabindex="-1">3.2 网络连载系列 <a class="header-anchor" href="#s-11" aria-label="Permalink to &quot;3.2 网络连载系列 {#s-11}&quot;">​</a></h3><h2 id="s-12" tabindex="-1">4. 体系性分析：看见→判断→行动→验证 <a class="header-anchor" href="#s-12" aria-label="Permalink to &quot;4. 体系性分析：看见→判断→行动→验证 {#s-12}&quot;">​</a></h2><h3 id="s-13" tabindex="-1">4.1 看见环节：5/5 <a class="header-anchor" href="#s-13" aria-label="Permalink to &quot;4.1 看见环节：5/5 {#s-13}&quot;">​</a></h3><p>地缘板块解构能力极强。能看到别人看不到的地理结构背后的规律，从山川河流到气候温度，从资源分布到文明边界，提供了一套独特的&quot;看地图&quot;能力。原创地图不是装饰，而是思维工具。</p><h3 id="s-14" tabindex="-1">4.2 判断环节：4.5/5 <a class="header-anchor" href="#s-14" aria-label="Permalink to &quot;4.2 判断环节：4.5/5 {#s-14}&quot;">​</a></h3><p>基于地缘结构做出战略判断的能力极强，多次精准预测已被历史验证。但判断主要停留在国家/文明层面，缺少对商业组织、产业链条、个人职业轨迹的地缘判断。</p><h3 id="s-15" tabindex="-1">4.3 行动环节：2/5 <a class="header-anchor" href="#s-15" aria-label="Permalink to &quot;4.3 行动环节：2/5 {#s-15}&quot;">​</a></h3><p><strong>这是最大的缺失环节。</strong> 内容基本停留在“看懂了世界”的层面，未告诉读者“看懂了之后怎么办”。完全缺失：企业地缘决策、个人职业地缘规划、地缘商业模式转换、地缘风控体系。</p><h3 id="s-16" tabindex="-1">4.4 验证环节：4/5 <a class="header-anchor" href="#s-16" aria-label="Permalink to &quot;4.4 验证环节：4/5 {#s-16}&quot;">​</a></h3><p>多次精准预测已被历史验证，但缺乏系统化的预测-验证机制，更像散点式历史印证。</p><h2 id="s-17" tabindex="-1">5. 闭环度分析 <a class="header-anchor" href="#s-17" aria-label="Permalink to &quot;5. 闭环度分析 {#s-17}&quot;">​</a></h2><p>**已闭环：**看见地缘规律 → 判断博弈格局 → 解释历史事件（回溯验证）</p><p>**未闭环：**<strong>判断博弈格局 → 个人/商业行动 → 结果反馈 → 调整判断</strong></p><h2 id="s-18" tabindex="-1">6. 可优化性分析 <a class="header-anchor" href="#s-18" aria-label="Permalink to &quot;6. 可优化性分析 {#s-18}&quot;">​</a></h2><h3 id="s-19" tabindex="-1">6.1 三个补充方向 <a class="header-anchor" href="#s-19" aria-label="Permalink to &quot;6.1 三个补充方向 {#s-19}&quot;">​</a></h3><p><strong>方向一：地缘视角→商业决策迁移</strong></p><p>将国家级地缘分析降维到企业级：供应链地缘风控、区域经济一体化中企业的地缘枢钮、企业&quot;地缘位置&quot;分析。</p><p><strong>方向二：地缘视角→个人决策迁移</strong></p><p>每个人都在某个地缘位置上。如何像分析一个国家一样分析自己的地缘资源？城市选择、行业选择、职业轨迹，都有地缘底层逻辑。</p><p><strong>方向三：地缘视角→制度设计与治理</strong></p><p>地缘视角不仅能解释历史，还能指导制度设计。联邦制在美国成功而在欧盟困难、东南亚媒体化治理而中东不能，地缘能给出答案。</p><h3 id="s-20" tabindex="-1">6.2 可优化性评估：4/5 <a class="header-anchor" href="#s-20" aria-label="Permalink to &quot;6.2 可优化性评估：4/5 {#s-20}&quot;">​</a></h3><p>**高度可优化。**温骏轩的地缘框架本身就是一套“元方法论”，可以被迁移到任何场景。缺的不是方法本身，而是方法的应用场景。只要补上“地缘→商业/个人决策”的桥梁，整个体系就能从“理解世界”升级为“改变世界”。</p><h2 id="s-21" tabindex="-1">7. 核心概念/命题清单 <a class="header-anchor" href="#s-21" aria-label="Permalink to &quot;7. 核心概念/命题清单 {#s-21}&quot;">​</a></h2><h2 id="s-22" tabindex="-1">8. 萃取建议 <a class="header-anchor" href="#s-22" aria-label="Permalink to &quot;8. 萃取建议 {#s-22}&quot;">​</a></h2><h3 id="s-23" tabindex="-1">8.1 书名建议 <a class="header-anchor" href="#s-23" aria-label="Permalink to &quot;8.1 书名建议 {#s-23}&quot;">​</a></h3><p><strong>主书名：****《地缘的觉醒——看见·判断·行动·验证》</strong></p><p><strong>副书名：</strong>《从地图里看出世界的底牌》或《版图之道：地缘视角下的博弈、决策与生存》</p><h3 id="s-24" tabindex="-1">8.2 结构建议 <a class="header-anchor" href="#s-24" aria-label="Permalink to &quot;8.2 结构建议 {#s-24}&quot;">​</a></h3><h2 id="s-25" tabindex="-1">导论：地缘是一种&quot;元视角&quot; <a class="header-anchor" href="#s-25" aria-label="Permalink to &quot;导论：地缘是一种&quot;元视角&quot; {#s-25}&quot;">​</a></h2><p>不是地理决定论，不是阴谋论，是一种看世界的方法。从《隆中对》到地缘分析，中国人其实从来不陌生。</p><p><strong>卷一：看见——地图里的规律</strong></p><p>地缘板块解构方法、新世界岛论、海陆双重优势、北纬42度温度线、热带悖论等核心概念的推演过程。</p><p><strong>卷二：判断——从地缘到博弈</strong></p><p>国家级博弈的地缘逻辑：中美博弈、中印博弈、中俄关系、欧盟自主意识的地缘根源。温骏轩的强项发挥到极致。</p><p><strong>卷三：行动——地缘视角的商业与个人迁移</strong></p><p><strong>最关键的填充卷，温骏轩未触及的领域。</strong> 包括：地缘视角下的企业战略、供应链地缘风控、个人职业规划的地缘思维、城市选择的地缘底层逻辑。</p><p><strong>卷四：验证——地缘与时间的交叉验证</strong></p><p>历史事件的地缘回溯验证，当代预测的持续追踪，建立精准预测清单和回准机制。</p><h2 id="s-26" tabindex="-1">结语：地缘视角是一种&quot;活的方法&quot; <a class="header-anchor" href="#s-26" aria-label="Permalink to &quot;结语：地缘视角是一种&quot;活的方法&quot; {#s-26}&quot;">​</a></h2><p>不是结论，是方法。掌握了这套方法，看得清地图、看得懂博弈、看得透未来。</p><h3 id="s-27" tabindex="-1">8.3 需要填充的空白 <a class="header-anchor" href="#s-27" aria-label="Permalink to &quot;8.3 需要填充的空白 {#s-27}&quot;">​</a></h3><h2 id="s-28" tabindex="-1">9. 关键引用/金句 <a class="header-anchor" href="#s-28" aria-label="Permalink to &quot;9. 关键引用/金句 {#s-28}&quot;">​</a></h2><p><em>1. &#39;地&#39;是环境，&#39;缘&#39;指人与人之间的关系。结合起来，就是以地理环境等客观因素为基础，研究以群体为单位的&#39;人&#39;，以及群体之间的关系。</em></p><p><em>2. 研究地缘学说的目的，并不在于否定人的作用，而在于正视环境的影响力，然后因势利导，在人力所及的范围内，让自己所处的环境更适应生存的需要。</em></p><p><em>3. 地是死的，人是活的。一个人出生的地缘环境，不等于他发展的地缘环境。商鞅、吕不韦、蒙氏家族……这些在秦国成就功业的名臣，哪个是秦人？</em></p><p><em>4. 我用的全是公开资料，我只是提供一种方法，谁掌握了都会得出同样的结论。就像情报分析，其实80%是基于公开可见的信息来分析的。</em></p><p><em>5. 读书的最终目的，是让人更宽容地理解世界的复杂性，这世上没有&#39;极左&#39;或&#39;极右&#39;，只有极端的偏激。</em></p><p><em>6. 在现实的国际关系中，血缘认同固然在一些合作问题上能够起到一定的积极作用，但最终决定国家之间关系的，还是各自的利益诉求。</em></p><p><em>7. 美国的地缘利益区是最大的，不过由此而潜伏的危险也是最大的。最有可能继印度之后登上大国舞台的国家就是巴西，如果巴西最终崛起的话，那才是美国衰弱的真正标志。</em></p><p><em>8. 当中国已经成为一个全球性大国时，拥有一个可以掌握的入洋通道就变得势在必行了。但这并不代表只是大陆需要台湾，事实上从安全角度考虑，台湾更加需要大陆。</em></p><h4 id="s-29" tabindex="-1">9. 良港后必有山，否则海岸线太过平滑，无法停泊大吨位船舶。 <a class="header-anchor" href="#s-29" aria-label="Permalink to &quot;9. 良港后必有山，否则海岸线太过平滑，无法停泊大吨位船舶。 {#s-29}&quot;">​</a></h4><p><em>10. 虽然在通常情况下，河流下游的冲积平原是最具地缘潜力的区域，但如果上游高地被其他国家控制的话，下游地区的地缘安全就很成问题了。</em></p><h2 id="s-30" tabindex="-1">10. 调研总结 <a class="header-anchor" href="#s-30" aria-label="Permalink to &quot;10. 调研总结 {#s-30}&quot;">​</a></h2><p>**温骏轩是当前中国民间地缘研究的绝对第一人。**他以17年持续创作、近1000万字的内容量、超过700张原创地图的视觉化表达、以及多次精准预测的历史验证，建立了一套从宏观到微观的地缘分析体系。</p><p>**他的核心价值在于提供了一套&quot;元方法论&quot;：**地缘板块解构法。这套方法可以被迁移到任何场景——只要有地理空间、有博弈关系，就可以用地缘视角解构。</p><p>**他的核心Gap在于闭环度不足：**内容停留在&quot;看懂世界&quot;层面，未提供&quot;用地缘视角改变世界&quot;的路径。这正是萃取时最值得填充的空白——将地缘框架从&quot;解释工具&quot;升级为&quot;决策工具&quot;。</p><p>**萃取价值判断：****极高。**温骏轩的体系是14位候选人中最完整的，他的地缘框架本身就是一套可迁移的思维方法论，而不仅仅是一堆观点的集合。只要补上&quot;行动闭环&quot;，整个体系就能从&quot;看懂世界&quot;升级为&quot;改变世界&quot;。</p>',94)])])}const q=e(r,[["render",p]]);export{d as __pageData,q as default};
